// PHASE 9: Nutrition & Diet Therapy (100 Questions)
const phase9 = {
  phase: 9, title: "Nutrition & Diet Therapy", icon: "🥗", color: "#e67e22",
  questions: [
    { id:"p9q1", question:"Which vitamin deficiency causes Scurvy?", options:["Vitamin A","Vitamin B12","Vitamin C (ascorbic acid)","Vitamin D"], answer:2, explanation:"Scurvy: Vitamin C deficiency. Signs: perifollicular hemorrhages, gum bleeding/swelling, poor wound healing, corkscrew hairs, joint pain. Vit C essential for collagen synthesis (hydroxylation of proline/lysine)." },
    { id:"p9q2", question:"Which mineral is essential for hemoglobin synthesis?", options:["Calcium","Zinc","Iron (Fe2+ — ferrous iron is absorbed; incorporated into heme)","Magnesium"], answer:2, explanation:"Iron is the central component of heme in hemoglobin (and myoglobin). Iron deficiency anemia: microcytic, hypochromic. Sources: red meat, legumes, fortified cereals. Vitamin C enhances non-heme iron absorption." },
    { id:"p9q3", question:"Normal BMI range for adults:", options:["15–18.5","18.5–24.9","25–29.9","30–34.9"], answer:1, explanation:"BMI: Underweight <18.5; Normal 18.5–24.9; Overweight 25–29.9; Obese Class I 30–34.9, Class II 35–39.9, Class III (morbid) ≥40. BMI doesn't account for muscle mass, age, or fat distribution." },
    { id:"p9q4", question:"Which fat-soluble vitamins can accumulate to toxic levels?", options:["B vitamins only","Vitamin C","A, D, E, K — fat-soluble, stored in adipose tissue and liver","Only vitamin A"], answer:2, explanation:"Fat-soluble vitamins (ADEK): stored in body fat and liver, can accumulate to toxic levels with excess supplementation. Water-soluble vitamins (B-complex, C): excreted in urine, less risk of toxicity." },
    { id:"p9q5", question:"Which macronutrient provides the MOST energy per gram?", options:["Carbohydrates (4 kcal/g)","Protein (4 kcal/g)","Fat (9 kcal/g — most energy dense)","Alcohol (7 kcal/g)"], answer:2, explanation:"Energy density: Fat = 9 kcal/g, Alcohol = 7 kcal/g, Carbohydrates = 4 kcal/g, Protein = 4 kcal/g. Fat is most energy-dense. Fiber ≈ 2 kcal/g (partially fermented by gut bacteria)." },
    { id:"p9q6", question:"Kwashiorkor is caused by:", options:["Total calorie deficiency","Protein deficiency with adequate caloric intake — edema (hypoalbuminemia), 'flag sign' in hair, moon face","Vitamin A deficiency","Iron deficiency"], answer:1, explanation:"Kwashiorkor: protein deficiency. Signs: edema (pitting — from hypoalbuminemia/low oncotic pressure), ascites, skin lesions, 'flaky paint' rash, 'flag sign' (alternating light/dark hair bands), moon face, enlarged fatty liver." },
    { id:"p9q7", question:"Marasmus is caused by:", options:["Protein deficiency only","Vitamin deficiency","Total calorie and protein deficiency (PEM) — severe wasting, 'old man' appearance, no edema","Mineral deficiency"], answer:2, explanation:"Marasmus: severe total energy and protein deficiency. Features: severe muscle and fat wasting, 'old man' face, prominent ribs, no edema (unlike kwashiorkor), growth retardation. Most common form of PEM globally." },
    { id:"p9q8", question:"Which vitamin is produced in the skin from sunlight exposure?", options:["Vitamin A","Vitamin B12","Vitamin C","Vitamin D (cholecalciferol — D3 from UV-B radiation)"], answer:3, explanation:"Vitamin D3 (cholecalciferol): synthesized in skin from 7-dehydrocholesterol + UV-B radiation. Converted to 25-OH-D3 in liver, then 1,25-(OH)2-D3 (calcitriol — active form) in kidney. Deficiency: rickets (children), osteomalacia (adults)." },
    { id:"p9q9", question:"A patient with phenylketonuria (PKU) requires a diet LOW in:", options:["Fats","Carbohydrates","Phenylalanine (low-phe formula — avoid aspartame, which contains phenylalanine)","Vitamin K"], answer:2, explanation:"PKU: inability to metabolize phenylalanine (PAH enzyme deficiency) → accumulates → brain damage. Diet: severely restrict phenylalanine-containing foods (all proteins) + phenylalanine-free formula as primary nutrition. Avoid aspartame (contains Phe)." },
    { id:"p9q10", question:"The recommended daily protein intake for a healthy adult is approximately:", options:["0.4 g/kg/day","0.8 g/kg/day (RDA)","1.5 g/kg/day","2.0 g/kg/day"], answer:1, explanation:"Protein RDA: 0.8 g/kg/day for healthy adults. Needs increase: pregnancy/lactation (1.1 g/kg), athletes (1.2–2.0 g/kg), critically ill (1.2–2.0 g/kg), renal failure (0.6–0.8 g/kg on non-dialysis)." },
    { id:"p9q11", question:"Which dietary modification is recommended for a patient with chronic kidney disease (CKD)?", options:["High protein, high potassium","Low protein, low potassium, low phosphorus, low sodium, fluid restriction","High fiber, high protein","No dietary restrictions needed"], answer:1, explanation:"CKD diet: low protein (reduces uremia/urea production), low potassium (prevent hyperkalemia), low phosphorus (prevent renal osteodystrophy), low sodium (reduce hypertension/fluid retention), fluid restriction (prevent fluid overload)." },
    { id:"p9q12", question:"Vitamin B12 deficiency causes:", options:["Microcytic hypochromic anemia","Megaloblastic anemia + subacute combined degeneration of the spinal cord (neurological damage)","Hemolytic anemia","Sideroblastic anemia"], answer:1, explanation:"Vitamin B12 deficiency: megaloblastic anemia (large immature RBCs), subacute combined degeneration (posterior + lateral column demyelination → ataxia, proprioception loss, spasticity), glossitis, peripheral neuropathy. Pernicious anemia: lack of intrinsic factor." },
    { id:"p9q13", question:"The DASH diet (Dietary Approaches to Stop Hypertension) emphasizes:", options:["High sodium, high fat","Low sodium (<2,300 mg/day), high fruits/vegetables, low-fat dairy, whole grains, nuts, limited red meat/sweets","Ketogenic diet","High protein diet only"], answer:1, explanation:"DASH diet: reduces SBP by 8–14 mmHg. Key: sodium <2,300 mg/day (ideally <1,500), 8–10 servings fruits/vegetables/day, low-fat dairy (3 servings), whole grains, nuts, beans, limited red/processed meat and sweets." },
    { id:"p9q14", question:"A patient with celiac disease must avoid:", options:["Dairy products","All fats","Gluten (wheat, barley, rye, and often oats if cross-contaminated)","Vitamin D"], answer:2, explanation:"Celiac disease: immune response to gliadin (gluten component) destroys small bowel villi. Strict lifelong gluten-free diet. Safe: rice, corn, potatoes, quinoa, sorghum. Unsafe: wheat (including spelt, kamut), barley, rye, most oats." },
    { id:"p9q15", question:"Refeeding syndrome risk is HIGHEST in:", options:["Obese patients","Severely malnourished patients (anorexia nervosa, prolonged fasting, severe weight loss)","Patients with mild malnutrition","Athletes"], answer:1, explanation:"Refeeding syndrome risk: severely malnourished (BMI <14, >10% weight loss in <2 months, >5 days minimal intake), chronic alcoholism, post-bariatric surgery, prolonged NPO. Mechanism: rapid carbs → insulin → cellular uptake of phosphate, K+, Mg2+ → severe hypophosphatemia." },
    { id:"p9q16", question:"Which vitamin deficiency causes night blindness?", options:["Vitamin C","Vitamin B1","Vitamin A (retinol — essential for rhodopsin synthesis in rod cells)","Vitamin E"], answer:2, explanation:"Vitamin A deficiency: night blindness (earliest sign), xerophthalmia (dry conjunctiva), Bitot's spots (foamy plaques on conjunctiva), keratomalacia (corneal ulceration → blindness), increased infection susceptibility, growth retardation." },
    { id:"p9q17", question:"Thiamine (Vitamin B1) deficiency causes:", options:["Pellagra","Scurvy","Beriberi (peripheral neuropathy — dry; or cardiac failure — wet) and Wernicke-Korsakoff syndrome","Rickets"], answer:2, explanation:"B1 (thiamine) deficiency: Dry beriberi (peripheral sensory/motor neuropathy), Wet beriberi (high-output cardiac failure, edema), Wernicke's encephalopathy (confusion, ophthalmoplegia, ataxia), Korsakoff syndrome (confabulation). Common in alcoholism." },
    { id:"p9q18", question:"Niacin (Vitamin B3) deficiency causes:", options:["Beriberi","Pellagra — the 4 D's: Dermatitis, Diarrhea, Dementia, Death","Scurvy","Rickets"], answer:1, explanation:"Pellagra (B3/niacin deficiency): 4 D's — Dermatitis (sun-exposed areas, 'Casal's necklace' on neck), Diarrhea (GI mucosa involvement), Dementia (CNS), Death if untreated. Common in populations relying on maize (corn) without alkali treatment (nixtamalization)." },
    { id:"p9q19", question:"The Mediterranean diet is associated with reduced risk of:", options:["Cancer only","Cardiovascular disease, type 2 diabetes, cognitive decline, and certain cancers","Infectious disease","Autoimmune disease only"], answer:1, explanation:"Mediterranean diet: olive oil (MUFA), fish, fruits/vegetables, legumes, whole grains, nuts, moderate wine, low red meat. Associated with reduced CVD, T2DM, metabolic syndrome, cognitive decline, and all-cause mortality." },
    { id:"p9q20", question:"Which type of fiber lowers blood cholesterol levels?", options:["Insoluble fiber (cellulose)","Soluble fiber (beta-glucan, pectin, psyllium) — binds bile acids in gut, excreted, liver uses cholesterol to make more bile","All fiber equally","Only animal-source fiber"], answer:1, explanation:"Soluble fiber (oats, barley, psyllium, legumes, apples, citrus): dissolves in water, forms gel → binds bile acids → fecal excretion → liver draws cholesterol from blood to synthesize new bile acids → lowers LDL. Insoluble fiber (wheat bran): improves bowel regularity." },
    { id:"p9q21", question:"A patient post-gastrectomy is at risk for which nutritional deficiency?", options:["Vitamin C only","Vitamin B12 (intrinsic factor lost), iron, calcium, fat-soluble vitamins — all require supplementation","Vitamin K only","Protein only"], answer:1, explanation:"Post-gastrectomy: intrinsic factor (IF) produced by gastric parietal cells → IF absent → B12 deficiency (pernicious anemia). Also: iron absorption (requires gastric acid), calcium (if duodenum bypassed), fat-soluble vitamins, dumping syndrome risk." },
    { id:"p9q22", question:"Total parenteral nutrition (TPN) is indicated when:", options:["Patient refuses oral intake for 1 day","GI tract is non-functional or inaccessible for >7 days — and nutritional needs cannot be met enterally","Patient needs extra protein","Patient is obese"], answer:1, explanation:"TPN: IV nutrition bypassing GI tract. Indicated: short bowel syndrome, intestinal obstruction, severe GI fistula, prolonged NPO with non-functional gut. Prefer enteral nutrition when gut functions — fewer complications, maintains gut integrity." },
    { id:"p9q23", question:"Which dietary fat is MOST harmful to cardiovascular health?", options:["Monounsaturated fat (MUFA)","Polyunsaturated fat (PUFA — omega-3/6)","Trans fat (partially hydrogenated oils) — raises LDL, lowers HDL","Omega-3 fatty acids"], answer:2, explanation:"Trans fats (partially hydrogenated oils): worst for CV health — raise LDL ('bad') AND lower HDL ('good') cholesterol. WHO target: eliminate industrial trans fats from global food supply by 2023 (REPLACE initiative)." },
    { id:"p9q24", question:"A patient with gout is advised to avoid:", options:["Dairy products","Purine-rich foods (organ meats, shellfish, red meat, beer) — purines metabolized to uric acid","All fruits","Vitamin C supplements"], answer:1, explanation:"Gout (hyperuricemia): avoid high-purine foods (organ meats — liver, kidney; shellfish — anchovies, sardines; red meat; beer/yeast extracts). Increase: low-fat dairy, cherries (reduce uric acid), water. Avoid fructose-sweetened beverages." },
    { id:"p9q25", question:"The glycemic index (GI) measures:", options:["Total carbohydrate content","How rapidly a food raises blood glucose compared to pure glucose (reference = 100)","Calorie content","Fiber content of food"], answer:1, explanation:"Glycemic index: measures speed of blood glucose rise after eating a food compared to pure glucose (GI=100). Low GI (<55): legumes, most fruits, oats. High GI (>70): white bread, white rice, potatoes, glucose. Glycemic load = GI × carb content ÷ 100." },
    { id:"p9q26", question:"Vitamin K is essential for:", options:["Immune function","Red blood cell production","Blood clotting (synthesis of factors II, VII, IX, X — 'C1972') and bone mineralization (osteocalcin)","Iron absorption"], answer:2, explanation:"Vitamin K: cofactor for carboxylation of clotting factors II (prothrombin), VII, IX, X. Deficiency: bleeding disorder. Sources: leafy greens (K1), gut bacteria (K2/menaquinone). Newborns lack gut bacteria → supplemental IM Vit K at birth." },
    { id:"p9q27", question:"Omega-3 fatty acids (EPA and DHA) are found in:", options:["Vegetable oils primarily","Fatty fish (salmon, sardines, mackerel), fish oil supplements, flaxseed (ALA — precursor)","Red meat","Dairy products mainly"], answer:1, explanation:"Omega-3 FA: EPA and DHA from fatty fish, fish oil. ALA from flaxseed, walnuts, chia seeds (converted inefficiently to EPA/DHA). Benefits: reduce triglycerides, anti-inflammatory, reduce CVD risk, fetal brain development." },
    { id:"p9q28", question:"Nutritional support should be initiated within how many hours in a critically ill patient?", options:["72 hours","48 hours","24–48 hours (early enteral nutrition — within 24–48h of ICU admission if hemodynamically stable)","7 days"], answer:2, explanation:"Early enteral nutrition (within 24–48 hours): maintains gut mucosal integrity (prevents bacterial translocation), preserves immune function, reduces infection risk, associated with better outcomes in critically ill patients." },
    { id:"p9q29", question:"Which diet is recommended for a patient with dumping syndrome after gastric surgery?", options:["Three large meals, high sugar","Small frequent meals (6/day), low simple sugars, high protein/fat/fiber, lie flat after eating","High carbohydrate diet","Liquid diet only"], answer:1, explanation:"Dumping syndrome: rapid gastric emptying → rapid glucose absorption (early) or reactive hypoglycemia (late). Management: small frequent meals, avoid simple sugars, increase protein and complex carbs, avoid drinking with meals, lie down 30 min post-meal." },
    { id:"p9q30", question:"A patient with liver cirrhosis and ascites requires which dietary modification?", options:["High sodium to replace losses","High protein, unrestricted sodium","Low sodium (<2,000 mg/day), adequate protein (1.2–1.5 g/kg/day to prevent muscle wasting), fluid restriction if severe hyponatremia","No dietary changes needed"], answer:2, explanation:"Cirrhosis with ascites: sodium restriction (<2,000 mg/day) to reduce fluid retention. Adequate protein (previously restricted but now recommended 1.2–1.5 g/kg to prevent sarcopenia). Fluid restriction only for severe dilutional hyponatremia (<125 mEq/L)." },
    { id:"p9q31", question:"Folate (folic acid) deficiency is associated with:", options:["Microcytic anemia","Megaloblastic anemia and neural tube defects (NTDs) in pregnancy","Hemolytic anemia","Iron deficiency anemia"], answer:1, explanation:"Folate (B9): essential for DNA synthesis (thymidylate synthesis). Deficiency: megaloblastic anemia (large immature RBCs — no neurological damage unlike B12). Periconceptional deficiency: neural tube defects (spina bifida, anencephaly)." },
    { id:"p9q32", question:"The recommended daily sodium intake for hypertensive patients is:", options:["<4,000 mg/day","<3,000 mg/day","<2,000–2,300 mg/day (DASH: <1,500 mg for maximal benefit)","No restriction needed"], answer:2, explanation:"Hypertension: AHA/ACC recommend <2,300 mg sodium/day for all adults; <1,500 mg for those with hypertension, CKD, or African Americans. Each 1,000 mg reduction in Na lowers SBP by ~2–4 mmHg." },
    { id:"p9q33", question:"Enteral nutrition (tube feeding) is preferred over TPN because:", options:["It is easier to administer","It maintains gut integrity, reduces bacterial translocation, preserves immune function, fewer serious complications, and is more cost-effective","It provides more calories","It avoids all nursing interventions"], answer:1, explanation:"Enteral nutrition (EN) advantages over TPN: maintains gut barrier (prevents bacterial translocation), stimulates GI hormones and immune function, lower infection risk (catheter sepsis, CLABSI from TPN), less expensive. 'If the gut works, use it.'" },
    { id:"p9q34", question:"A patient on warfarin therapy should maintain consistent intake of:", options:["Vitamin C-rich foods","Vitamin K-rich foods (leafy greens) — not necessarily restrict, but maintain CONSISTENCY to keep INR stable","Iron-rich foods","Calcium-rich foods"], answer:1, explanation:"Warfarin and Vitamin K: fluctuating Vit K intake destabilizes INR. Patients should eat consistent amounts of Vit K-containing foods (kale, spinach, broccoli) — not necessarily avoid them. Sudden increase: lowers INR; sudden decrease: raises INR." },
    { id:"p9q35", question:"Which blood lipid level is PROTECTIVE against cardiovascular disease?", options:["High LDL","Low HDL","High HDL (>60 mg/dL is protective)","High triglycerides"], answer:2, explanation:"HDL ('good' cholesterol): transports cholesterol from peripheral tissues to liver for excretion (reverse cholesterol transport). High HDL (>60 mg/dL) is protective. Low HDL (<40 men, <50 women) is a major CVD risk factor." },
    { id:"p9q36", question:"Total daily calorie requirement for an average adult male (sedentary):", options:["1,200–1,400 kcal","1,600–1,800 kcal","2,000–2,500 kcal","3,000–3,500 kcal"], answer:2, explanation:"Average calorie needs: Sedentary adult female: ~1,600–2,000 kcal; Male: ~2,000–2,500 kcal. Active individuals: 2,400–3,000 kcal. Critically ill: 25–30 kcal/kg/day. Obese critically ill: 11–14 kcal/kg actual weight." },
    { id:"p9q37", question:"The term 'bioavailability' in nutrition refers to:", options:["Total nutrient content of food","Proportion of a nutrient that is digested, absorbed, and utilized by the body","Speed of digestion","Calorie content only"], answer:1, explanation:"Bioavailability: fraction of ingested nutrient that reaches systemic circulation and is available for use. Factors affecting it: food matrix, cooking method, gut health, nutrient interactions (e.g., Vit C enhances non-heme iron bioavailability)." },
    { id:"p9q38", question:"A patient has been NPO for 3 days and requires nasogastric tube feeding. Before starting the feed, the nurse should:", options:["Start the feed at full rate","Verify tube placement (X-ray or pH), elevate HOB 30–45°, and start at low rate progressing gradually","Check blood glucose only","Remove all other IV lines"], answer:1, explanation:"Before starting NG tube feeding: confirm placement (X-ray gold standard, or pH <5.5), HOB ≥30°, start at 10–20 mL/hr and titrate up over 24–48 hours, check residuals, monitor glucose, assess tolerance (distension, nausea)." },
    { id:"p9q39", question:"Iodine deficiency causes:", options:["Kwashiorkor","Scurvy","Goiter and hypothyroidism — iodized salt is the major preventive measure","Rickets"], answer:2, explanation:"Iodine: essential for thyroid hormone (T3, T4) synthesis. Deficiency: goiter (thyroid enlargement), hypothyroidism, cretinism (intellectual disability if in utero). Prevention: universal salt iodization. Most common preventable cause of intellectual disability globally." },
    { id:"p9q40", question:"Which trace element is essential for insulin function and glucose metabolism?", options:["Iron","Zinc","Chromium (enhances insulin receptor sensitivity)","Selenium"], answer:2, explanation:"Chromium: potentiates insulin action by facilitating glucose uptake into cells. Deficiency (rare, usually in long-term TPN without chromium supplementation): glucose intolerance, peripheral neuropathy." },
    { id:"p9q41", question:"A patient with pancreatitis is typically started on nutrition in which form first?", options:["NPO with only IV fluids indefinitely","TPN via central line always","Early enteral nutrition (within 24–48h via NG/NJ tube if tolerated) is now preferred over TPN in acute pancreatitis","High-fat oral diet"], answer:2, explanation:"Acute pancreatitis: early EN (nasal-jejunal or nasal-gastric) is now preferred over TPN — reduces infection, maintains gut barrier, similar or better outcomes. Mild pancreatitis: restart oral low-fat diet when pain/nausea resolve. TPN only if EN not feasible." },
    { id:"p9q42", question:"Zinc deficiency signs include:", options:["Night blindness","Bleeding gums","Impaired wound healing, taste/smell loss (hypogeusia/anosmia), alopecia, dermatitis, immune dysfunction","Peripheral neuropathy"], answer:2, explanation:"Zinc deficiency: impaired wound healing (zinc cofactor for collagen synthesis), loss of taste and smell, alopecia, dermatitis (acrodermatitis enteropathica — genetic), immune dysfunction (T-cell deficiency), growth retardation, male hypogonadism." },
    { id:"p9q43", question:"Which diet is recommended after an acute MI?", options:["No dietary changes","Heart-healthy diet: Mediterranean or DASH, low saturated fat, trans fat-free, low sodium, high fiber, fruits/vegetables, omega-3 fish","High protein diet only","Low carbohydrate ketogenic diet"], answer:1, explanation:"Post-MI diet: heart-healthy dietary pattern (Mediterranean or DASH), reduce saturated fat (<7% energy), eliminate trans fats, omega-3 fatty acids (fish 2×/week), increase soluble fiber, reduce sodium, achieve and maintain healthy weight." },
    { id:"p9q44", question:"What is the recommended daily fiber intake for adults?", options:["10–15 g/day","25–38 g/day (women 25g, men 38g — most adults consume only 10–15g)","50–60 g/day","5–10 g/day"], answer:1, explanation:"Dietary fiber DRI: women 25 g/day, men 38 g/day (or 14g per 1,000 kcal). Benefits: reduce LDL, improve glycemic control, promote satiety, prevent constipation, reduce colon cancer risk. Most adults consume only 10–15 g/day." },
    { id:"p9q45", question:"Night eating syndrome is characterized by:", options:["Eating during the day only","Morning anorexia, evening hyperphagia (>25% calories after dinner), nocturnal eating (after awakening), insomnia","Binge eating during daylight hours","Refusing food at all meals"], answer:1, explanation:"Night eating syndrome: morning anorexia (no appetite), eating >25% of daily calories after the evening meal, awakening from sleep to eat ≥3 times per week, depression/stress-related, associated with obesity and metabolic syndrome." },
    { id:"p9q46", question:"A patient with diabetes is taught about carbohydrate counting. One carbohydrate serving equals:", options:["10 grams","15 grams of carbohydrate","25 grams","50 grams"], answer:1, explanation:"Carbohydrate counting (diabetes management): 1 carb serving = 15 grams of carbohydrate. Most adults with T1DM use insulin-to-carb ratios (e.g., 1 unit insulin per 15g carbs). Consistent carb intake helps stabilize blood glucose." },
    { id:"p9q47", question:"Selenium deficiency is associated with:", options:["Goiter","Anemia","Keshan disease (dilated cardiomyopathy) and impaired thyroid function","Scurvy"], answer:2, explanation:"Selenium: component of glutathione peroxidase (antioxidant enzyme) and selenoproteins involved in thyroid hormone metabolism. Deficiency: Keshan disease (cardiomyopathy — endemic in China), thyroid dysfunction, impaired immunity." },
    { id:"p9q48", question:"A patient is on continuous enteral tube feeding. High gastric residual volume (GRV) indicates:", options:["The tube is in the correct position","Aspiration risk — gastric emptying is delayed; hold feeding if GRV >250–500 mL (per protocol)","Good absorption","The patient needs more calories"], answer:1, explanation:"High GRV (>250–500 mL or per institution protocol): indicates delayed gastric emptying and aspiration risk. Interventions: elevate HOB ≥30°, hold feeding temporarily, consider prokinetics (metoclopramide, erythromycin), consider post-pyloric feeding." },
    { id:"p9q49", question:"Which nutritional supplement is recommended for vegans?", options:["Iron only","Vitamin B12 (not found in plant foods), Vitamin D, iodine, calcium, zinc, and omega-3 (DHA/EPA)","Vitamin C only","No supplements needed with careful vegan diet"], answer:1, explanation:"Vegan diet supplementation: Vitamin B12 (ESSENTIAL — no plant sources; deficiency causes irreversible neurological damage), Vitamin D3 (from lichen-based source), iodine (if no iodized salt), calcium, zinc, long-chain omega-3 (algae-based DHA)." },
    { id:"p9q50", question:"Harris-Benedict equation is used to calculate:", options:["Blood glucose","Body surface area","Basal metabolic rate (BMR) — then multiplied by activity factor to get total energy expenditure","Body mass index"], answer:2, explanation:"Harris-Benedict equation: calculates BMR (energy needed at rest). BMR × activity factor = Total Daily Energy Expenditure (TDEE). Mifflin-St Jeor equation is now more commonly used (more accurate). ICU: indirect calorimetry is gold standard." },
    { id:"p9q51", question:"Low albumin level in a hospitalized patient most commonly indicates:", options:["Adequate nutritional status","Recent malnutrition","Inflammation/acute illness (negative acute phase reactant) — serum albumin is a poor marker of short-term nutritional status","Liver cancer"], answer:2, explanation:"Albumin (half-life 20 days): reflects chronic nutritional status BUT also falls rapidly during acute illness/inflammation (negative acute phase protein). Prealbumin (half-life 2–3 days) better reflects acute changes. C-reactive protein: assess inflammation confounding." },
    { id:"p9q52", question:"Which electrolyte is the PRIMARY intracellular cation?", options:["Sodium","Calcium","Potassium (K+ — 98% intracellular, maintained by Na+/K+ ATPase pump)","Magnesium"], answer:2, explanation:"Potassium: primary INTRACELLULAR cation (K+ ~150 mEq/L intracellular vs. 3.5–5.0 mEq/L extracellular). Crucial for resting membrane potential, cardiac conduction, muscle contraction. Serum K+ reflects only 2% of total body K+." },
    { id:"p9q53", question:"Which diet is recommended for a patient with peptic ulcer disease?", options:["High-spice, high-coffee diet","Avoid NSAIDs, limit alcohol and caffeine, small frequent meals, test and treat H. pylori — no strict dietary restrictions otherwise","Strict milk and cream diet (Sippy diet — now obsolete)","High fat, low acid foods only"], answer:1, explanation:"Modern PUD management: there is NO evidence that specific foods cause ulcers. Avoid NSAIDs (use paracetamol instead), limit alcohol, caffeine in excess, and smoking. H. pylori eradication (triple therapy) is the main treatment. Bland Sippy diet is outdated." },
    { id:"p9q54", question:"Essential amino acids are those that:", options:["Can be synthesized by the body","Must be obtained from the diet because the body cannot synthesize them","Are only found in animal products","Are only needed during childhood"], answer:1, explanation:"9 essential amino acids (must come from diet): Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine. (Mnemonic: 'His Ile Leu Lys Met Phe Thr Trp Val'). Complete proteins contain all 9." },
    { id:"p9q55", question:"A patient receiving TPN develops hyperglycemia. The nurse should:", options:["Stop TPN immediately","Decrease the TPN infusion rate and/or add insulin to the TPN bag per protocol","Increase the infusion rate","Add more dextrose to the TPN"], answer:1, explanation:"TPN hyperglycemia: target blood glucose 140–180 mg/dL. Management: reduce dextrose concentration, add regular insulin to TPN bag, or use insulin infusion. TPN-related hyperglycemia is associated with increased infection risk (impairs neutrophil function)." },
    { id:"p9q56", question:"The type of malnutrition characterized by loss of both fat and muscle mass (wasting + low weight):", options:["Kwashiorkor","Marasmus (primary energy malnutrition — 'dry' PEM)","Mixed marasmic kwashiorkor","Micronutrient deficiency only"], answer:1, explanation:"Marasmus: severe reduction in total energy intake → catabolism of both fat (wasting) and muscle (atrophy). Appears emaciated, 'skin and bones.' No edema (distinguishes from kwashiorkor). Most common in infants in developing countries." },
    { id:"p9q57", question:"Which dietary pattern is recommended to reduce colorectal cancer risk?", options:["High red and processed meat intake","High fiber, fruits, vegetables, whole grains, limited red meat (<18 oz/week cooked), no processed meat, limit alcohol","High fat, low fiber","Keto diet"], answer:1, explanation:"Colorectal cancer prevention: WHO/WCRF recommend high fiber diet (protective), limit red meat (<500g cooked/week), avoid processed meats (classified Group 1 carcinogen), maintain healthy weight, regular physical activity, limit alcohol." },
    { id:"p9q58", question:"Which fluid is the recommended oral rehydration solution (ORS) for diarrhea?", options:["Plain water only","Sports drinks (Gatorade) — adequate","WHO ORS (glucose + sodium + potassium + bicarbonate in specific concentrations)","Fruit juice"], answer:2, explanation:"WHO ORS: 2.6g NaCl, 1.5g KCl, 2.9g Na citrate, 13.5g glucose per liter. Glucose promotes Na cotransport in intestine (SGLT1) even during diarrhea. Plain water: no electrolytes. Sports drinks: too high sugar, too low Na. Fruit juice: too high sugar, too low Na, too much potassium." },
    { id:"p9q59", question:"Calcium deficiency in adults causes:", options:["Rickets","Scurvy","Osteoporosis (long-term) and hypocalcemia (acute — tetany, paresthesia, Chvostek's sign)","Pellagra"], answer:2, explanation:"Calcium deficiency: acute → hypocalcemia (tetany, muscle cramps, paresthesia, seizures, Chvostek's/Trousseau's signs, prolonged QT). Chronic → osteoporosis (reduced bone mineral density → fracture risk). Sources: dairy, leafy greens, fortified foods." },
    { id:"p9q60", question:"Which food is HIGHEST in potassium?", options:["White rice","Chicken breast","Bananas, potatoes, avocado, spinach, beans — all high potassium sources","White bread"], answer:2, explanation:"High potassium foods: banana (422 mg), potato (926 mg), avocado (975 mg), spinach, sweet potato, beans, tomatoes, yogurt. Important for patients on diuretics (need more K+) and CKD (need less K+)." },
    { id:"p9q61", question:"A patient has just had a colostomy and is concerned about diet. The nurse advises:", options:["Avoid all fruits and vegetables","No dietary restrictions at all","Eat low-fiber diet initially, progress to balanced diet, identify personal food triggers for gas/odor, stay well hydrated","Only liquid diet permanently"], answer:2, explanation:"Colostomy diet: start low-fiber post-surgery, progress to balanced diet over weeks. Identify foods causing gas (beans, cabbage, carbonated drinks) and odor (eggs, fish, onions). Drink 8-10 cups water/day. Most foods tolerated with trial and error." },
    { id:"p9q62", question:"Pre-albumin (transthyretin) is a better marker of acute nutritional status than albumin because:", options:["It is more stable","It has a shorter half-life (2–3 days vs albumin 20 days) — responds faster to nutritional changes","It is not affected by inflammation","It is cheaper to measure"], answer:1, explanation:"Pre-albumin (transthyretin): short half-life 2–3 days → reflects recent nutritional status changes more accurately. However, also a negative acute phase reactant → falls during inflammation regardless of nutrition. Best interpreted with CRP." },
    { id:"p9q63", question:"Essential fatty acids that humans cannot synthesize include:", options:["Oleic acid (omega-9)","Linoleic acid (omega-6) and alpha-linolenic acid (omega-3)","Palmitic acid","Stearic acid"], answer:1, explanation:"Essential fatty acids (EFAs): Linoleic acid (LA, omega-6) and Alpha-linolenic acid (ALA, omega-3) — humans lack delta-12 and delta-15 desaturases. From these, EPA, DHA (omega-3) and arachidonic acid (omega-6) are synthesized (inefficiently)." },
    { id:"p9q64", question:"A patient with type 2 diabetes has HbA1c of 9.5%. Dietary counseling focuses on:", options:["Increasing sugar intake","Consistent carbohydrate intake (45–60g per meal), low GI foods, increase fiber, reduce added sugars, portion control, Mediterranean/DASH pattern","No dietary modification needed — just medication","Eliminating all carbohydrates"], answer:1, explanation:"T2DM nutritional therapy: consistent carb intake (not elimination — 45–60g/meal), choose low GI/high fiber carbs, reduce added sugars and refined carbs, healthy fats, lean protein, Mediterranean or DASH dietary pattern for overall cardiometabolic benefit." },
    { id:"p9q65", question:"Which clinical sign indicates vitamin D toxicity?", options:["Night blindness","Hypercalcemia (nausea, vomiting, weakness, confusion, polyuria, constipation, kidney stones)","Peripheral neuropathy","Bleeding tendency"], answer:1, explanation:"Vitamin D toxicity: excessive supplementation → hypercalcemia (Vitamin D toxicity is due to hypercalcemia, not direct Vit D effects). Symptoms: nausea, vomiting, weakness, confusion, polyuria/polydipsia, constipation, kidney stones, metastatic calcification." },
    { id:"p9q66", question:"Sodium content in 1 teaspoon of table salt (NaCl) is approximately:", options:["500 mg","1,000 mg","2,300 mg","3,000 mg"], answer:2, explanation:"1 teaspoon of table salt (NaCl) ≈ 2,300 mg sodium — exactly the AHA daily sodium limit for healthy adults. Patients on low-sodium diets (1,500 mg/day) should use ≤2/3 tsp salt total from ALL sources daily." },
    { id:"p9q67", question:"Which nutrient plays the most important role in wound healing?", options:["Carbohydrates","Vitamin K","Protein and vitamin C (collagen synthesis requires both amino acids + vitamin C for hydroxylation)","Iron alone"], answer:2, explanation:"Wound healing key nutrients: Protein (essential for collagen, fibroblast, immune function — goal 1.2–2.0 g/kg/day), Vitamin C (collagen hydroxylation), Zinc (cofactor for collagen synthesis, immune function), adequate calories to spare protein, Vitamin A." },
    { id:"p9q68", question:"A breastfeeding mother is advised to increase her daily calorie intake by approximately:", options:["100 kcal/day","300–500 kcal/day above pre-pregnancy needs","1,000 kcal/day","No extra calories needed"], answer:1, explanation:"Lactation energy needs: approximately 300–500 kcal/day above pre-pregnancy baseline (to produce ~750 mL breast milk/day). Continue prenatal vitamins, increase fluid intake. Protein needs also increase (~71g/day vs 46g non-pregnant)." },
    { id:"p9q69", question:"Low carbohydrate (ketogenic) diet causes weight loss through which PRIMARY mechanism?", options:["Blocking fat absorption","Ketosis suppresses appetite and forces fat oxidation for fuel — also initial water loss from glycogen depletion","Increasing protein synthesis only","Reducing calorie absorption"], answer:1, explanation:"Ketogenic diet (<50g carbs/day): glycogen depletion → water loss (rapid initial weight loss), ketosis (fat→ketones for fuel), appetite suppression (ketones and high protein). Long-term sustainability and safety (especially renal, cardiac) are concerns." },
    { id:"p9q70", question:"Which population group has the HIGHEST risk of iron deficiency anemia?", options:["Adult males","Postmenopausal women","Premenopausal women, pregnant women, infants 6–24 months, adolescent girls","Elderly men only"], answer:2, explanation:"Highest iron deficiency risk: pregnant women (increased demand), premenopausal women (menstrual losses), infants 6–24 months (rapid growth, low iron breast milk after 6 months), adolescent girls. Global: 1.6 billion people have iron deficiency anemia." },
    { id:"p9q71", question:"The role of phosphorus in the body includes:", options:["Only bone formation","Energy metabolism (ATP), bone/teeth mineralization (hydroxyapatite), DNA/RNA structure, cell membrane (phospholipids), acid-base balance","Only cell signaling","Blood clotting only"], answer:1, explanation:"Phosphorus: 85% in bones/teeth (hydroxyapatite), remainder in soft tissues. Functions: ATP synthesis (energy currency), DNA/RNA backbone, phospholipid membranes, intracellular signaling, 2,3-DPG (oxygen delivery). Deficiency: rare, seen in refeeding syndrome." },
    { id:"p9q72", question:"A patient with short bowel syndrome (SBS) is at risk for which specific deficiency?", options:["Only protein","Vitamin B12 (terminal ileum resected — site of B12 absorption), fat-soluble vitamins, calcium, magnesium, and zinc","Only vitamin C","Protein and carbohydrates only"], answer:1, explanation:"SBS deficiencies depend on resected segment: Ileum resection → B12 malabsorption (requires intrinsic factor, absorbed in terminal ileum), bile salt malabsorption → fat malabsorption → fat-soluble vitamin deficiency (ADEK), calcium, magnesium, zinc deficiency." },
    { id:"p9q73", question:"What is the purpose of a clear liquid diet?", options:["Provide maximum nutrition","Reduce colon bacterial load and minimize GI residue before procedures/surgery — does NOT provide adequate nutrition for >3 days","Treat malnutrition","Provide high fiber intake"], answer:1, explanation:"Clear liquid diet: water, clear broth, fruit juice without pulp, Jell-O, popsicles, tea/coffee without milk. Used pre-procedure/surgery (bowel prep, endoscopy), after surgery to restart diet, acute vomiting. Inadequate nutrition if prolonged." },
    { id:"p9q74", question:"Vitamin E deficiency in adults is MOST commonly associated with:", options:["Increased infection risk","Fat malabsorption disorders (Crohn's, cystic fibrosis) — causes hemolytic anemia and peripheral neuropathy","Bleeding tendency","Night blindness"], answer:1, explanation:"Vitamin E (alpha-tocopherol): fat-soluble antioxidant. Primary deficiency rare; secondary to fat malabsorption. Signs: hemolytic anemia (protects RBC membranes from oxidative damage), peripheral neuropathy, ataxia, retinopathy. Sources: nuts, seeds, vegetable oils." },
    { id:"p9q75", question:"Probiotic foods (yogurt, kefir, kimchi) provide:", options:["Prebiotics (fiber for bacteria)","Live beneficial microorganisms that may improve gut microbiome, immune function, and reduce diarrhea","Antibiotics naturally","Anti-inflammatory drugs"], answer:1, explanation:"Probiotics: live microorganisms (Lactobacillus, Bifidobacterium) that confer health benefits when consumed in adequate amounts. Benefits: reduce antibiotic-associated diarrhea (C. diff), improve lactose intolerance, support immune function. Evidence varies by strain and indication." },
    { id:"p9q76", question:"A patient with iron deficiency anemia is prescribed oral ferrous sulfate. The nurse teaches that absorption is ENHANCED by:", options:["Taking with milk or antacids","Taking on an empty stomach with vitamin C (orange juice)","Taking with tea or coffee","Taking after meals with calcium supplements"], answer:1, explanation:"Iron absorption enhanced: Vitamin C (reduces Fe3+ to Fe2+, which is better absorbed), acidic environment (empty stomach), meat factor (heme iron). Inhibitors: tea/coffee (tannins), dairy (calcium), antacids, phytates (whole grains), oxalates (spinach)." },
    { id:"p9q77", question:"Total protein requirement per day for a critically ill, mechanically ventilated patient:", options:["0.4 g/kg/day","0.8 g/kg/day","1.2–2.0 g/kg/day (higher in burns, sepsis, obesity — up to 2.5 g/kg IBW)","3.0 g/kg/day"], answer:2, explanation:"Critically ill patients: protein 1.2–2.0 g/kg/day (SCCM/ASPEN guidelines). Higher in: burns (1.5–2.0 g/kg), obesity (2.0–2.5 g/kg IBW to preserve lean mass during hypocaloric feeding), sepsis, trauma. Adequate protein reduces mortality and ICU LOS." },
    { id:"p9q78", question:"Which dietary modification reduces risk of kidney stones (calcium oxalate — most common type)?", options:["Low calcium diet","High fluid intake (>2.5 L/day), normal calcium intake (1,000 mg/day), low sodium (<2,300 mg/day), low animal protein, moderate oxalate restriction","High protein diet","Vitamin C supplements"], answer:1, explanation:"Calcium oxalate stones: high fluid intake (dilutes urine), normal dietary calcium (not restriction — dietary Ca binds intestinal oxalate reducing absorption), low sodium (reduces urine calcium), low animal protein (reduces uric acid and calcium excretion), limit oxalate-rich foods (spinach, beets, nuts)." },
    { id:"p9q79", question:"Which nutritional screening tool is commonly used in hospitals?", options:["CAGE questionnaire","NRS-2002 (Nutritional Risk Screening 2002), MUST (Malnutrition Universal Screening Tool), or MNA (Mini Nutritional Assessment for elderly)","PHQ-9","MMSE"], answer:1, explanation:"NRS-2002: recommended by ESPEN for hospitalized patients — screens nutritional status (BMI, weight loss, dietary intake) and disease severity. MUST: community/outpatient. MNA: specifically for elderly (≥65 years). All identify malnutrition risk." },
    { id:"p9q80", question:"A patient with hypertriglyceridemia is advised to limit:", options:["Monounsaturated fats","Omega-3 fatty acids (these reduce triglycerides)","Simple sugars, refined carbohydrates, and alcohol — all raise triglycerides","Protein intake"], answer:2, explanation:"Hypertriglyceridemia dietary management: reduce simple sugars (fructose), refined carbs, alcohol (most potent trigger), increase omega-3 fatty acids (fish oil reduces TG by 25–50%), reduce total fat if severe (>1,000 mg/dL to prevent pancreatitis)." },
    { id:"p9q81", question:"Fasting plasma glucose is checked after how many hours of fasting?", options:["4 hours","8 hours (minimum 8 hours, typically overnight)","12 hours only","2 hours"], answer:1, explanation:"Fasting glucose test: minimum 8 hours fasting (no caloric intake, water allowed). Normal: 70–99 mg/dL. Impaired fasting glucose (prediabetes): 100–125 mg/dL. Diabetes: ≥126 mg/dL on 2 separate occasions." },
    { id:"p9q82", question:"Biotin (Vitamin B7) deficiency can be caused by:", options:["Excessive vitamin C intake","Consuming large amounts of raw egg whites (avidin binds biotin)","Low protein diet","High fat diet"], answer:1, explanation:"Biotin deficiency: rare. Caused by: raw egg white (avidin — glycoprotein that avidly binds biotin, preventing absorption), long-term antibiotic use (kills biotin-producing gut bacteria), long-term TPN without biotin supplementation, biotinidase deficiency (genetic)." },
    { id:"p9q83", question:"Riboflavin (Vitamin B2) deficiency causes:", options:["Pellagra","Angular cheilitis (cracks at corners of mouth), glossitis (magenta tongue), seborrheic dermatitis, corneal vascularization","Beriberi","Scurvy"], answer:1, explanation:"B2 (riboflavin) deficiency: Angular cheilitis (stomatitis), glossitis (tongue inflammation, magenta/purple color), seborrheic dermatitis, normochromic normocytic anemia, corneal vascularization. Sources: dairy, eggs, lean meats, fortified grains." },
    { id:"p9q84", question:"A patient with pancreatitis is started on enteral nutrition. Which tube feeding ACCESS is preferred?", options:["Nasogastric (stomach) — high flow rate","Nasojejunal (NJ) tube — bypasses the stomach and duodenum to avoid stimulating pancreatic secretions","Total parenteral nutrition always","Oral feeding immediately"], answer:1, explanation:"Pancreatitis enteral feeding: NJ tube (nasojejunal) or NG tube is preferred. NJ bypasses the pancreatic stimulation trigger (gastric feeding stimulates pancreatic secretion less than thought, but NJ is used for severe pancreatitis). Both are better than TPN." },
    { id:"p9q85", question:"Which food group has the HIGHEST phosphorus content?", options:["Fruits","Vegetables","Dairy products, meat, fish, legumes, nuts, and whole grains","White bread and rice"], answer:2, explanation:"High phosphorus foods: dairy (milk, cheese), meat, fish, nuts, legumes, whole grains, dark cola drinks (phosphoric acid). Restricted in CKD patients to prevent hyperphosphatemia and secondary hyperparathyroidism." },
    { id:"p9q86", question:"A patient with hypothyroidism is advised about which food interactions:", options:["Avoid vitamin C foods","Take levothyroxine on empty stomach, 30–60 min before food — soy, calcium, iron, and high-fiber foods interfere with absorption","Avoid all proteins","Increase iodine supplementation excessively"], answer:1, explanation:"Levothyroxine absorption: take 30–60 min before breakfast on empty stomach. Foods that interfere: soy products, high-calcium foods, high-fiber (bran), coffee. Supplements to avoid within 4 hours: iron, calcium, antacids (reduce absorption by 25–40%)." },
    { id:"p9q87", question:"MUAC (Mid-Upper Arm Circumference) <12.5 cm in children 6–59 months indicates:", options:["Normal nutritional status","Severe acute malnutrition (SAM) requiring therapeutic feeding","Mild malnutrition only","Obesity"], answer:1, explanation:"MUAC: quick field assessment for acute malnutrition. <11.5 cm = SAM (severe acute malnutrition — immediate treatment with RUTF — ready-to-use therapeutic food). 11.5–12.5 cm = MAM (moderate acute malnutrition). >12.5 cm = adequate." },
    { id:"p9q88", question:"A patient with end-stage renal disease on hemodialysis — protein intake recommendation:", options:["Very low protein 0.4 g/kg/day","Low protein 0.6 g/kg/day (pre-dialysis non-dialysis patients)","Higher protein 1.2–1.4 g/kg/day (dialysis patients lose amino acids during dialysis)","No protein restriction"], answer:2, explanation:"ESRD on dialysis protein needs: 1.2–1.4 g/kg/day (higher than non-dialysis CKD) because amino acids are lost during hemodialysis sessions. Pre-dialysis CKD: 0.6–0.8 g/kg/day to slow progression." },
    { id:"p9q89", question:"What percentage of daily calories should come from fat (WHO recommendation)?", options:["10–15%","20–35% (with <10% saturated, <1% trans fats)","40–50%","<10%"], answer:1, explanation:"WHO macronutrient recommendations: Fat 20–35% (adult), Saturated fat <10%, Trans fat <1%, Carbohydrates 45–65%, Protein 10–35%. Healthy oils: olive, canola, nuts, avocado. Limit: butter, palm oil, coconut oil, lard." },
    { id:"p9q90", question:"The MOST important dietary intervention to slow progression of diabetic nephropathy is:", options:["High protein diet","Restricting carbohydrates only","Protein restriction (0.6–0.8 g/kg/day) and strict glucose control (HbA1c <7%)","Avoiding all sodium"], answer:2, explanation:"Diabetic nephropathy progression: protein restriction (0.6–0.8 g/kg/day) reduces intraglomerular pressure and proteinuria. Combined with strict glycemic control (HbA1c <7%), BP control (<130/80) with ACE inhibitor/ARB, and low sodium diet." },
    { id:"p9q91", question:"Dietary intake of trans fatty acids should be limited to:", options:["<10% of total energy","<5% of total energy","As low as possible — WHO target: <1% of total energy (ideally eliminate)","<2% of total energy only"], answer:2, explanation:"Trans fat: WHO recommends <1% of total energy (ideally eliminate industrial trans fats completely). WHO REPLACE initiative targets elimination of partially hydrogenated oils globally by 2023. Trans fats raise LDL, lower HDL, cause inflammation." },
    { id:"p9q92", question:"A malnourished patient develops severe hypophosphatemia (PO4 <1.5 mg/dL) after starting nutrition. This is:", options:["Normal response to nutrition","Refeeding syndrome — insulin drives phosphate into cells, causing life-threatening hypophosphatemia","Iron deficiency","Dehydration"], answer:1, explanation:"Refeeding syndrome: carbohydrate reintroduction → insulin surge → cellular uptake of phosphate, K+, Mg2+ → severe hypophosphatemia (most dangerous — causes respiratory failure, cardiac dysfunction, hemolytic anemia, seizures). Prevent by gradual feeding and electrolyte supplementation." },
    { id:"p9q93", question:"The dietary therapy for phenylketonuria (PKU) aims to maintain phenylalanine blood levels:", options:["As high as possible","120–360 μmol/L (normal range for treated PKU)","Zero phenylalanine in the diet (not achievable or needed)","Only restricting during childhood"], answer:1, explanation:"PKU dietary therapy: restrict phenylalanine to minimum needed for growth (some is essential for protein synthesis) while maintaining blood Phe levels within therapeutic range (120–360 μmol/L). Lifelong restriction recommended, especially during pregnancy (maternal PKU)." },
    { id:"p9q94", question:"Adequate hydration status is BEST assessed by:", options:["Thirst alone","Urine color (pale yellow = adequate; dark amber = dehydrated), urine output, and serum osmolality","Weight only","Blood pressure only"], answer:1, explanation:"Hydration assessment: urine color (1–3 pale yellow = adequate), UO 0.5–1 mL/kg/hr, serum osmolality 275–295 mOsm/kg, body weight changes. Thirst is a late indicator — especially unreliable in elderly who have reduced thirst sensation." },
    { id:"p9q95", question:"Children's fluid requirements per day are calculated using which formula?", options:["500 mL for all ages","Holliday-Segar method: 100 mL/kg for first 10 kg + 50 mL/kg for next 10 kg + 20 mL/kg for each kg above 20 kg","30 mL/kg for all pediatric patients","1 L for all children"], answer:1, explanation:"Holliday-Segar maintenance fluid calculation: First 10 kg → 100 mL/kg/day; Next 10 kg (10–20 kg) → 50 mL/kg/day; Each kg above 20 → 20 mL/kg/day. Example: 25 kg child = 1000+500+100 = 1,600 mL/day." },
    { id:"p9q96", question:"Pyridoxine (Vitamin B6) toxicity from excess supplementation causes:", options:["Night blindness","Peripheral sensory neuropathy (numbness, ataxia — paradoxically same as deficiency at very high doses)","Renal failure","Liver toxicity"], answer:1, explanation:"B6 (pyridoxine) toxicity: doses >200 mg/day (some: >50 mg/day) can cause sensory neuropathy — paresthesias, ataxia, photosensitivity. Paradoxically, both deficiency and toxicity can cause neuropathy. UL: 100 mg/day for adults." },
    { id:"p9q97", question:"The Mediterranean diet's most protective component for cardiovascular health is:", options:["Red wine (moderate)","High meat intake","Extra-virgin olive oil (rich in oleocanthal — anti-inflammatory, and oleic acid — MUFA)","Dairy products"], answer:2, explanation:"EVOO (extra-virgin olive oil): primary fat in Mediterranean diet. Rich in oleic acid (MUFA — reduces LDL oxidation), polyphenols (oleocanthal — natural anti-inflammatory, similar to ibuprofen), and antioxidants. PREDIMED trial: reduces CV events by 30%." },
    { id:"p9q98", question:"Which micronutrient deficiency is most commonly associated with alcoholism?", options:["Vitamin A","Vitamin D","Thiamine (Vitamin B1), folate, magnesium, and zinc — all commonly deficient in alcohol use disorder","Vitamin K"], answer:2, explanation:"Alcoholism nutritional deficiencies: Thiamine (B1) — most critical (causes Wernicke-Korsakoff), Folate (B9), Magnesium, Zinc, B6, Niacin. Give IV thiamine BEFORE glucose in alcohol-related altered consciousness to prevent Wernicke's precipitation." },
    { id:"p9q99", question:"Recommended water intake for adults (WHO):", options:["500 mL/day","At least 2 L/day from all sources (water, beverages, food) — more with heat/exercise/fever","1 L/day is sufficient","5 L/day minimum"], answer:1, explanation:"WHO recommends at least 2 L (about 8 cups) of total fluid intake daily under normal conditions. About 20% comes from food. Needs increase with: hot weather, physical activity, fever, diarrhea, pregnancy/lactation, kidney stones." },
    { id:"p9q100", question:"Which clinical finding suggests malnutrition in a hospitalized patient?", options:["BMI 22","Bilateral pitting edema, muscle wasting, hair changes, weight loss >5% in 1 month, low albumin <3.5 g/dL","Normal strength","Good appetite"], answer:1, explanation:"Malnutrition indicators: unintentional weight loss (>5%/1 month, >10%/6 months), BMI <18.5, reduced food intake (<50% needs for >1 week), low albumin (<3.5), muscle wasting (temporal/interosseous muscles), edema from hypoalbuminemia, delayed wound healing." }
  ]
};
export default phase9;
